array_map(
			function ( $item ) {
				if ( $this->format === 'json' ) {
					return $this->convert_to_json( $item );
				} elseif ( $this->format === 'csv' ) {
					return $this->convert_to_csv( $item );
				} elseif ( $this->format === 'sql' ) {
					return $this->convert_to_sql( $item );
				}

				return $item;
			}, $results['results']
		)

array_map(
			function ( $column ) {
				global $wpdb;

				$column_schema = $this->schema->get_column( $column->get_column_id() );

				if ( $column_schema !== null && $column_schema->get_type() === 'integer' ) {
					return $wpdb->prepare( '%d', $column->get_value() );
				}

				return $wpdb->prepare( '%s', $column->get_value() );
			}, $result->get_columns()
		)

array_map(
			function ( $column ) {
				if ( ! $column instanceof Modifier\Value\String_Value ) {
					  return false;
				}

				$replace = $column->get_replace_value();
				if ( $replace === null ) {
					return false;
				}

				if ( has_shortcode( $replace, 'column' ) ) {
					$result = do_shortcode( $replace );

					if ( preg_match_all( '/column::(.*?)\s/', $result, $matches ) > 0 ) {
						foreach ( $matches[1] as $match ) {
							   return $column->get_schema()->get_source() . '__' . $match;
						}
					}
				}

				return false;
			}, $this->columns
		)

array_map(
				function ( $preset ) {
					unset( $preset['id'] );

					if ( isset( $preset['tags'] ) && $preset['tags'] === [] ) {
						unset( $preset['tags'] );
					}

					if ( isset( $preset['locked'] ) && $preset['locked'] === [] ) {
						unset( $preset['locked'] );
					}

					return $preset;
				}, Search\Preset::get_all()
			)

array_map(
			function ( $filter ) use ( $schema ) {
				$new_filter = new Filter( $filter, $schema );

				if ( $new_filter->is_valid() ) {
					  return $new_filter;
				}

				return false;
			}, array_slice( $json, 0, self::MAX_AND_FILTERS )
		)

array_map(
					function ( $item ) {
						if ( is_numeric( $item ) ) {
							  return intval( $item, 10 );
						}

						return $item;
					}, $item['values']
				)

array_map(
			function ( $tag ) {
				if ( ! is_array( $tag ) ) {
					return false;
				}

				$title = isset( $tag['title'] ) ? $tag['title'] : '';
				$name = isset( $tag['name'] ) ? $tag['name'] : '';

				$title = $this->sanitize( $title );
				$name = $this->sanitize( $name );

				if ( $title !== '' && $name !== '' ) {
					return [
						'title' => $title,
						'name' => $name,
					];
				}

				return false;
			}, $tags
		)

array_map(
			function ( $item ) use ( $meta ) {
				$value = new Type\Value( $meta[ $item ][0] );

				return [
					'key' => $item,
					'value' => $meta[ $item ][0],
					'value_type' => $value->get_value_type(),
				];
			}, array_keys( $meta )
		)

array_filter(
			$this->get_schema()['columns'], function ( $column ) {
				if ( isset( $column['join'] ) ) {
					return false;
				}

				if ( isset( $column['modify'] ) && $column['modify'] === false ) {
					return false;
				}

				return true;
			}
		)

array_map(
			function ( $term ) use ( $type ) {
				if ( $type === 'slug' ) {
					  return $term->slug;
				}

				if ( $type === 'url' ) {
					$link = get_term_link( $term );
					if ( is_wp_error( $link ) ) {
						return '';
					}
					return $link;
				}

				if ( $type === 'link' ) {
					$link = get_term_link( $term );
					if ( $link instanceof WP_Error ) {
						return '';
					}

					return '<a href="' . esc_url( $link ) . '">' . $term->name . '</a>';
				}

				if ( $type === 'description' ) {
					return $term->description;
				}

				return $term->name;
			}, $terms
		)

array_filter(
			array_map(
				function ( $query ) {
					if ( $query ) {
						return $query->get_as_sql();
					}

					return false;
				},
				$queries
			),
			fn( $v ) => $v !== false
		)

array_map(
				function ( $query ) {
					if ( $query ) {
						return $query->get_as_sql();
					}

					return false;
				},
				$queries
			)

array_filter(
			$items, function ( $item ) use ( $joins ) {
				foreach ( $joins as $join ) {
					if ( $item->is_column_match( $join->get_column() ) ) {
						return false;
					}
				}

				return true;
			}
		)

array_map(
			function ( $item ) use ( $wpdb ) {
				if ( is_numeric( $item ) ) {
					return $wpdb->prepare( '%d', $item );
				}

				return $wpdb->prepare( '%s', $item );
			}, $this->value
		)
